def _dbt_metric_to_nested(dbt_metric: DbtMetric) -> DbtMetricNested:
    """Convert flat DbtMetric to nested format."""
    attrs = DbtMetricAttributes()
    _populate_dbt_metric_attrs(attrs, dbt_metric)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_metric, _DBT_METRIC_REL_FIELDS, DbtMetricRelationshipAttributes
    )
    return DbtMetricNested(
        guid=dbt_metric.guid,
        type_name=dbt_metric.type_name,
        status=dbt_metric.status,
        version=dbt_metric.version,
        create_time=dbt_metric.create_time,
        update_time=dbt_metric.update_time,
        created_by=dbt_metric.created_by,
        updated_by=dbt_metric.updated_by,
        classifications=dbt_metric.classifications,
        classification_names=dbt_metric.classification_names,
        meanings=dbt_metric.meanings,
        labels=dbt_metric.labels,
        business_attributes=dbt_metric.business_attributes,
        custom_attributes=dbt_metric.custom_attributes,
        pending_tasks=dbt_metric.pending_tasks,
        proxy=dbt_metric.proxy,
        is_incomplete=dbt_metric.is_incomplete,
        provenance_type=dbt_metric.provenance_type,
        home_id=dbt_metric.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _dbt_metric_from_nested(nested: DbtMetricNested) -> DbtMetric:
    """Convert nested format to flat DbtMetric."""
    attrs = nested.attributes if nested.attributes is not UNSET else DbtMetricAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_METRIC_REL_FIELDS,
        DbtMetricRelationshipAttributes
    )
    return DbtMetric(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_dbt_metric_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _dbt_metric_to_nested_bytes(dbt_metric: DbtMetric, serde: Serde) -> bytes:
    """Convert flat DbtMetric to nested JSON bytes."""
    return serde.encode(_dbt_metric_to_nested(dbt_metric))


def _dbt_metric_from_nested_bytes(data: bytes, serde: Serde) -> DbtMetric:
    """Convert nested JSON bytes to flat DbtMetric."""
    nested = serde.decode(data, DbtMetricNested)
    return _dbt_metric_from_nested(nested)

